/*
Créateur Baptiste - Trésorier 2025-2026

v1.0 - 06/05/2025
v1.1 - 06/02/2026 
  * lister les avenants pour les CE
  * corrige erreur increment inf quand il n'y a pas de FI
  * corrige erreur formatage montant 
  * possibilité de choisir le dossier cible
*/

const idTemplate = "";

const formateurEuro = new Intl.NumberFormat('fr-FR', {
  style: 'currency',
  currency: 'EUR',
});

function findTable (body, caseHautGauche) {
  // Phase ou Synthèse
  const tables = body.getTables();

  let tableauTrouve = null;

  // Chercher le tableau contenant "Phase" en haut à gauche
  for (let i = 0; i < tables.length; i++) {
    const table = tables[i];
    if (table.getNumRows() > 0 && table.getCell(0, 0).getText().trim() === caseHautGauche) {
      tableauTrouve = table;
      break;
    }
  }

  if (!tableauTrouve) {
    Logger.log(`Aucun tableau avec '${caseHautGauche}' trouvé.`);
    return null;
  }

  return tableauTrouve;
}

function getInformationsEtude(sheet) {
  return {
    isCE: sheet.getRange("C1").getValue(),
    referenceEtude: sheet.getRange("C2").getValue(),
    nomEtude: sheet.getRange("C3").getValue(),
    referenceAvenant: sheet.getRange("C4").getValue(),
    entreprise: sheet.getRange("K2").getValue(),
    contact: sheet.getRange("K3").getValue(),
    poste: sheet.getRange("K4").getValue(),
    adresse: sheet.getRange("K5").getValue(),
    ville: sheet.getRange("K6").getValue(),
    siren: sheet.getRange("K7").getValue(),
    delaisPaiement: sheet.getRange("K9").getValue()
  };
}

function hasAcompte(sheetFacture) {
  return sheetFacture.getRange("C7").getValue() > 0; // Montant de l’acompte
}

function getInformationsFacture(infos, incrementFacture, incrementFactureEtude, dateFin) {
  let texteAvenant = "";

  if (infos.referenceAvenant) {
    if (infos.isCE) {
      // Extraction du numéro N (le chiffre entre les deux premiers tirets)
      // Exemple : "ACE-3-22XXXX" -> match[1] vaudra "3"
      const match = infos.referenceAvenant.match(/ACE-(\d+)-/);

      if (match) {
        const dernierNumero = parseInt(match[1], 10);
        const prefixe = "ACE-";
        const suffixe = infos.referenceAvenant.split(match[1])[1]; // Récupère "-22XXXX"

        // Création de la liste : ACE-1-..., ACE-2-..., ACE-3-...
        const listeAvenants = Array.from({ length: dernierNumero }, (_, i) => `${prefixe}${i + 1}${suffixe}`);

        texteAvenant = `(modifiée par ${listeAvenants.join(", ")})`;
      } else {
        // Fallback si le format ne correspond pas parfaitement
        texteAvenant = `(modifiée par ${infos.referenceAvenant})`;
      }
    } else {
      // Logique pour les Bons de Commande (rectifié par...)
      texteAvenant = `(rectifié par ${infos.referenceAvenant})`;
    }
  }

  return {
    referenceFacture: `FAC-${incrementFacture}-${infos.referenceEtude}-${incrementFactureEtude}`,
    dateFacture: Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "dd/MM/yyyy"),
    dateEcheance: Utilities.formatDate(
      new Date(Date.now() + (infos.delaisPaiement || 0) * 24 * 60 * 60 * 1000),
      Session.getScriptTimeZone(), "dd/MM/yyyy"
    ),
    typeContrat: infos.isCE ? "Convention d’étude" : "Bon de commande",
    refContrat: `${infos.isCE ? "CE" : "BC"}-${infos.referenceEtude}`,
    avenant: texteAvenant,
    dateSignaturePVR: dateFin ? `Date de signature du PVR : ${dateFin}` : ""
  };
}

function creerFacture(referenceFacture, docTemplateId, dossierDestinationId) {
  const modele = DriveApp.getFileById(docTemplateId);

  let dossier;
  try {
    dossier = DriveApp.getFolderById(dossierDestinationId);

    // Petite sécurité supplémentaire : vérifier qu'on a bien accès au dossier
    // (parfois l'ID existe mais on n'a pas les droits)
    dossier.getName(); 

  } catch (e) {
    Browser.msgBox("Erreur : Impossible de trouver le dossier. Vérifiez que l'ID '" + dossierDestinationId + "' est correct et que vous avez les droits d'accès.");
    return null;
  }

  const copie = modele.makeCopy(referenceFacture, dossier);
  const doc = DocumentApp.openById(copie.getId());
  return doc;
}

function remplacerVariables(body, infos, infosFacture, typeFacture) {
  const variables = {
    "{{Adresse}}": infos.adresse,
    "{{Avenant}}": infosFacture.avenant,
    "{{Contact}}": infos.contact,
    "{{Date}}": infosFacture.dateFacture,
    "{{Date signature PVR}}": infosFacture.dateSignaturePVR,
    "{{Date échéance}}": infosFacture.dateEcheance,
    "{{Dénomination étude}}": infos.nomEtude,
    "{{Entreprise}}": infos.entreprise,
    "{{Etude n°}}": infos.referenceEtude,
    "{{Poste}}": infos.poste,
    "{{ref contrat}}": infosFacture.refContrat,
    "{{ref facture}}": infosFacture.referenceFacture,
    "{{SIREN}}": infos.siren,
    "{{Type de contrat}}": infosFacture.typeContrat,
    "{{Type facture}}": typeFacture,
    "{{Ville}}": infos.ville
  }  

  for (const [cle, valeur] of Object.entries(variables)) {
    body.replaceText(cle, valeur.toString());
  }
}

function remplirTableauPhases(table, data, nbFacture) {
  let totalPresta = 0;
  let sumJEH = 0;
  let nbLignesInserees = 0;

  for (let i = 0; i < data.length; i++) {
    const [num, intitule, prixJEH, nbJEH, prixPhase, facture] = data[i];
    if (!num) break;
    if (nbFacture != null && facture != nbFacture) continue;

    totalPresta += prixPhase;
    sumJEH += nbJEH;

    const row = table.insertTableRow(nbLignesInserees + 1);
    nbLignesInserees++;
    const ligne = [
      String(num),
      String(intitule),
      formateurEuro.format(prixJEH),
      String(nbJEH),
      formateurEuro.format(prixPhase)
    ];
    ligne.forEach(val => row.appendTableCell(val));
  }

  const numRows = table.getNumRows();
  const numCols = table.getRow(numRows - 1).getNumCells();
  table.getCell(numRows - 1, numCols - 1).setText(formateurEuro.format(totalPresta));
  table.getCell(numRows - 1, numCols - 2).setText(String(sumJEH));
}

function remplirTableauSynthese(table, data) {
  for (let i = 0; i < data.length; i++) {
    const [nom, montant] = data[i];
    if (!nom) break;
    if (montant == 0) continue;

    const montantFormate = formateurEuro.format(montant);
    const row = table.appendTableRow();
    row.appendTableCell(nom);
    row.appendTableCell(montantFormate);
  }
}

function genererFactureAcompte() {
  const sheetPhases = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Phases");
  const sheetFacture = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Facture");
  const infos = getInformationsEtude(sheetPhases);

  const incrementFacture = Browser.inputBox("Quel est le numéro d'incrémentation globale de la facture ?");
  const infosFacture = getInformationsFacture(infos, incrementFacture, 1, null);

  const idDossierCible = Browser.inputBox("Quel est l'id du dossier dans lequel vous voulez enregistrer la facture ?");
  const doc = creerFacture(infosFacture.referenceFacture, idTemplate, idDossierCible);
  if (doc == null) {
    return;
  }

  const body = doc.getBody();

  remplacerVariables(body, infos, infosFacture, "d’acompte");

  const tablePhase = findTable(body, "Phase");
  const tableSynthese = findTable(body, "Synthèse");

  if (!tablePhase || !tableSynthese) {
    SpreadsheetApp.getUi().alert("Impossible de trouver le tableau des phases ou celui de synthèse dans le GDoc");
    return;
  }

  remplirTableauPhases(tablePhase, sheetPhases.getRange("B10:G").getValues(), null);
  remplirTableauSynthese(tableSynthese, sheetFacture.getRange("B4:C9").getValues());

  doc.saveAndClose();

  const dossierOutput = DriveApp.getFolderById(idDossierCible); 
  SpreadsheetApp.getUi().alert("Facture d'acompte enregistrée dans " + dossierOutput.getName());
}

function trouverLigneFactureIntermediaire(sheetFacture, numFacture) {
  const valeurs = sheetFacture.getRange("E5:E").getValues(); 

  for (let i = 0; i < valeurs.length; i++) {
    if (valeurs[i][0] == numFacture) {
      const ligneTrouvee = i + 5; // car on commence à la ligne 5 (E5)
      return ligneTrouvee;
    }

    if (valeurs[i][0] == "") {
      return null;
    }
  }
}

function dataSyntheseFacIntermediaire(sheetFacture, ligneFactureIntermedaire) {
  const ligne = sheetFacture.getRange(`F${ligneFactureIntermedaire}:H${ligneFactureIntermedaire}`).getValues();
  const data = [];

  for (let i = 0; i < ligne[0].length; i++){
    let colonneEntete = String.fromCharCode('F'.charCodeAt(0) + i);
    let entete = sheetFacture.getRange(`${colonneEntete}4`).getValue();
    data.push([entete, ligne[0][i]]);
  }
  return data;
}

function genererFactureIntermediaire() {
  const sheetPhases = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Phases");
  const sheetFacture = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Facture");
  const infos = getInformationsEtude(sheetPhases);

  const incrementFacture = Browser.inputBox("Quel est le numéro d'incrémentation globale de la facture ?");
  const numFacture = Browser.inputBox("Quel est le numéro de la facture intermédiaire ?");

  const ligneFactureIntermedaire = trouverLigneFactureIntermediaire(sheetFacture, numFacture);
  if (!ligneFactureIntermedaire) {
    SpreadsheetApp.getUi().alert("Impossible de trouver cette facture intermédiaire");
    return;
  }

  const incrementFactureEtude = hasAcompte(sheetFacture) ? numFacture + 1 : numFacture; // +1 pour la facture d'acompte

  const dateSignaturePVRBrut = sheetFacture.getRange(`I${ligneFactureIntermedaire}`).getValue();
  const dateSignaturePVR = Utilities.formatDate(dateSignaturePVRBrut, Session.getScriptTimeZone(), "dd/MM/yyyy");
  const infosFacture = getInformationsFacture(infos, incrementFacture, incrementFactureEtude, dateSignaturePVR);

  const idDossierCible = Browser.inputBox("Quel est l'id du dossier dans lequel vous voulez enregistrer la facture ?");
  const doc = creerFacture(infosFacture.referenceFacture, idTemplate, idDossierCible);
  if (doc == null) {
    return;
  }
  const body = doc.getBody();

  remplacerVariables(body, infos, infosFacture, "intermédiaire");

  const tablePhase = findTable(body, "Phase");
  const tableSynthese = findTable(body, "Synthèse");

  if (!tablePhase || !tableSynthese) {
    SpreadsheetApp.getUi().alert("Impossible de trouver le tableau des phases ou celui de synthèse dans le GDoc");
    return;
  }

  remplirTableauPhases(tablePhase, sheetPhases.getRange("B10:G").getValues(), numFacture);
  remplirTableauSynthese(tableSynthese, dataSyntheseFacIntermediaire(sheetFacture, ligneFactureIntermedaire));

  doc.saveAndClose();

  const dossierOutput = DriveApp.getFolderById(idDossierCible); 
  SpreadsheetApp.getUi().alert("Facture intermédiaire enregistrée dans " + dossierOutput.getName());
}

function trouverDerniereFactureIntermediraire(sheetPhases) {
  const valeurs = sheetPhases.getRange("G10:G").getValues();

  // On filtre pour ne garder que les nombres
  const nombres = valeurs.flat().filter(val => typeof val === "number" && !isNaN(val));

  // Si le tableau est vide, Math.max renvoie -Infinity, on utilise || 0 pour renvoyer 0
  const max = Math.max(...nombres);

  return max === -Infinity ? 0 : max;
}

function genererFactureSolde() {
  const sheetPhases = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Phases");
  const sheetFacture = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Facture");
  const infos = getInformationsEtude(sheetPhases);

  const incrementFacture = Browser.inputBox("Quel est le numéro d'incrémentation globale de la facture ?");
  const numFacture = trouverDerniereFactureIntermediraire(sheetPhases) + 1; // +1 pour compte la facture de solde
  const dateSignaturePVRBrut = sheetFacture.getRange("L12").getValue();
  const dateSignaturePVR = Utilities.formatDate(dateSignaturePVRBrut, Session.getScriptTimeZone(), "dd/MM/yyyy");
  const incrementFactureEtude = hasAcompte(sheetFacture) ? numFacture + 1 : numFacture;  // +1 pour la facture d'acompte
  const infosFacture = getInformationsFacture(infos, incrementFacture, incrementFactureEtude, dateSignaturePVR); 

  const idDossierCible = Browser.inputBox("Quel est l'id du dossier dans lequel vous voulez enregistrer la facture ?");
  const doc = creerFacture(infosFacture.referenceFacture, idTemplate, idDossierCible);
  if (doc == null) {
    return;
  }
  const body = doc.getBody();

  remplacerVariables(body, infos, infosFacture, "de solde");

  const tablePhase = findTable(body, "Phase");
  const tableSynthese = findTable(body, "Synthèse");

  if (!tablePhase || !tableSynthese) {
    SpreadsheetApp.getUi().alert("Impossible de trouver le tableau des phases ou celui de synthèse dans le GDoc");
    return;
  }

  remplirTableauPhases(tablePhase, sheetPhases.getRange("B10:G").getValues(), "finale");
  remplirTableauSynthese(tableSynthese, sheetFacture.getRange("K4:L10").getValues());

  doc.saveAndClose();

  const dossierOutput = DriveApp.getFolderById(idDossierCible); 
  SpreadsheetApp.getUi().alert("Facture de solde enregistrée dans " + dossierOutput.getName());
}
